const d = $input.first().json;

if (!d || !d.thread_id) {
  return [{ json: { skip: true, reason: 'No active threads with 0 touchpoints' } }];
}

let propertyContext = 'Address: ' + d.address + ', ' + d.city + ', ' + d.state + '\n';
if (d.property_type) propertyContext += 'Type: ' + d.property_type + '\n';
if (d.list_price) propertyContext += 'List Price: $' + Number(d.list_price).toLocaleString() + '\n';
if (d.days_on_market) propertyContext += 'Days on Market: ' + d.days_on_market + '\n';
if (d.listing_status) propertyContext += 'Listing Status: ' + d.listing_status + '\n';
propertyContext += 'Broker: ' + d.full_name;

const firstName = d.first_name || d.full_name.split(' ')[0];

// Framed as ghostwriting/drafting — avoids AI refusal triggers
const prompt = 'Draft a short cold text message for a commercial real estate buyer reaching out to a broker about their listing.\n\nSender background: Filip Shnayder, Manager at Kumo Capital. Owner-operator, $265M+ AUM, acquires multi-tenant industrial and flex properties between $5M-$40M in the Southeast and Midwest.\n\nListing info:\n' + propertyContext + '\n\nDraft requirements:\n- Open with the broker first name: ' + firstName + '\n- Maximum 2-3 sentences. Written as a casual text, not an email.\n- Direct and confident. Buyer has seen the listing and is interested.\n- Close with one soft qualifying question about occupancy, tenancy mix, or whether they have an OM/package ready.\n- No sign-off, no subject line, no formatting. Pure text message body only.\n\nOutput the draft message text only — nothing else.';

return [{ json: {
  thread_id: d.thread_id,
  contact_id: d.contact_id,
  property_id: d.property_id,
  listing_id: d.listing_id || '',
  phone: d.phone_number,
  broker_first_name: firstName,
  prompt,
  skip: false
} }];

const ctx = $('Prepare Outreach Context').first().json;
const raw = $input.first().json;

let reply = '';
try {
  if (raw.content && Array.isArray(raw.content)) {
    const textBlock = raw.content.find(function(b) { return b.type === 'text'; });
    if (textBlock) reply = textBlock.text.trim();
  }
} catch(e) {}

// Detect refusal patterns — swap with fallback before anything gets sent
const refusalPatterns = [
  /I cannot engage/i,
  /I.m not able to/i,
  /I apologize/i,
  /as an AI/i,
  /I.m an AI/i,
  /fictional identit/i,
  /roleplay/i,
  /unethical/i,
  /harmful/i,
  /I.m sorry/i
];

const isRefusal = !reply || refusalPatterns.some(function(p) { return p.test(reply); });

if (isRefusal) {
  // Hardcoded natural fallbacks — rotate randomly so it varies
  const fallbacks = [
    'Hey ' + ctx.broker_first_name + ', saw your listing on Crexi — we buy multi-tenant industrial and flex in that range. Got an OM or package ready?',
    ctx.broker_first_name + ', came across your listing. We close on multi-tenant commercial in the $5M-$40M range. Is this stabilized or is there vacancy to work with?',
    'Hey ' + ctx.broker_first_name + ' — Fil Shnayder at Kumo Capital. Your listing caught my eye. What does the tenancy look like?'
  ];
  reply = fallbacks[Math.floor(Math.random() * fallbacks.length)];
}

const wordCount = reply.split(/\s+/).length;
const delaySec = Math.max(3, Math.min(3 + Math.ceil(wordCount / 40) + Math.random() * 4, 12));

return [{ json: {
  reply,
  phone: ctx.phone,
  thread_id: ctx.thread_id,
  contact_id: ctx.contact_id,
  property_id: ctx.property_id,
  listing_id: ctx.listing_id,
  delay_seconds: delaySec
} }];

const d = $('Extract Reply').first().json;

function safeStr(v) {
  return String(v == null ? '' : v).replace(/'/g, "''");
}

const tid = safeStr(d.thread_id);
const rep = safeStr(d.reply);

if (!tid) {
  return [{ json: { query: 'SELECT 1 -- no thread_id' } }];
}

const query = [
  "INSERT INTO app.messages (thread_id, direction, sender, body, sent_at)",
  "VALUES ('" + tid + "'::uuid, 'outbound'::message_direction, 'bot'::message_sender, '" + rep + "', NOW());",
  "",
  "UPDATE app.message_threads",
  "SET touchpoint_count = touchpoint_count + 1,",
  "    last_outreach_at = NOW(),",
  "    next_followup_at = NOW() + INTERVAL '48 hours',",
  "    updated_at = NOW()",
  "WHERE id = '" + tid + "'::uuid;"
].join('\n');

return [{ json: { query, reply: d.reply, phone: d.phone, thread_id: d.thread_id } }];

const d = $('Build Log SQL').first().json;
return [{ json: {
  status: 'sent',
  phone: d.phone,
  thread_id: d.thread_id,
  message_sent: d.reply
} }];
